import type { PaginationRootProps } from '@/vendor/untitled-ui/application/pagination/pagination-base';
import {
  PaginationPageDefault,
  PaginationPageMinimalCenter,
  PaginationCardMinimal,
  PaginationButtonGroup,
} from '@/vendor/untitled-ui/application/pagination/pagination';
import { WithDataId } from '@/types/withDataId';

export type PaginationProps = Omit<PaginationRootProps, 'children'> & {
  type?: 'default' | 'page-minimal-center' | 'card-minimal' | 'button-group';
  rounded?: boolean;
  align?: 'center' | 'left' | 'right';
} & WithDataId;

export const Pagination = (props: PaginationProps) => {
  const { type = 'default', align = 'center', page, ...restProps } = props;

  const onPageChange = (p: number) => {
    if (restProps.onPageChange) {
      restProps.onPageChange(p);
    }
  };

  switch (type) {
    case 'page-minimal-center':
      return (
        <PaginationPageMinimalCenter
          {...restProps}
          page={page}
          onPageChange={onPageChange}
        />
      );
    case 'card-minimal':
      return (
        <PaginationCardMinimal
          {...restProps}
          align={align}
          page={page}
          onPageChange={onPageChange}
        />
      );
    case 'button-group':
      return (
        <PaginationButtonGroup
          {...restProps}
          align={align}
          page={page}
          onPageChange={onPageChange}
        />
      );
    default:
      return (
        <PaginationPageDefault
          {...restProps}
          page={page}
          onPageChange={onPageChange}
        />
      );
  }
};
